#include "hmc5883l.h"
#include <Wire.h>
#include <Adafruit_HMC5883_U.h>
#include <math.h>
static Adafruit_HMC5883_Unified mag(12345);
static float _x=0,_y=0,_z=0,_heading=0;static unsigned long _l=0;
void hmc5883l_setup(){Wire.begin();if(!mag.begin()){Serial.println("[hmc5883l] Fail!");return;}Serial.println("[hmc5883l] OK");}
void hmc5883l_loop(){if(millis()-_l<100)return;_l=millis();sensors_event_t e;mag.getEvent(&e);_x=e.magnetic.x;_y=e.magnetic.y;_z=e.magnetic.z;_heading=atan2(_y,_x)*180.0/M_PI;if(_heading<0)_heading+=360;}
float hmc5883l_get_heading(){return _heading;}
float hmc5883l_get_x(){return _x;}
float hmc5883l_get_y(){return _y;}
float hmc5883l_get_z(){return _z;}
